  ('pukao-7c4986e7-moex-00264', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '下列何者可以解釋長期平均成本隨產量遞減的現象？', '["平均固定成本隨產量遞減", "固定規模報酬", "邊際生產力遞減", "專業分工"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00265', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '衝浪板製造過程中的投入產出與成本間的關係如下：若產量為10單位時，總成本為100，增用一單位生產 因素後產量為12，總成本變為130，邊際成本為何？', '["30", "20", "15", "10"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
